import tarfile
import os


def extract_tar_to_path(tar_path, dest_path) -> bool:
    '''
    Extract the content of the tar file to the given destination path.
    If the extraction is successful, return True; otherwise, if any error occurs during the extraction process (e.g. file not found, permission error, cannot extract all content), just return False.

    Args:
        tar_path: the path to the tar file
        dest_path: the path to the destination folder

    Returns:
        True if the extraction is successful; otherwise, False
    '''
    def is_within_directory(directory, target):
        abs_directory = os.path.abspath(directory)
        abs_target = os.path.abspath(target)
        prefix = os.path.commonpath([abs_directory, abs_target])
        return prefix == abs_directory

    def safe_extract(tar, path):
        for member in tar.getmembers():
            member_path = os.path.join(path, member.name)
            if not is_within_directory(path, member_path):
                raise Exception("Path traversal detected in tar file")
            # Reject symlinks/hardlinks that point outside destination
            if member.issym() or member.islnk():
                link_target = os.path.join(
                    os.path.dirname(member_path), member.linkname
                )
                if not is_within_directory(path, link_target):
                    raise Exception("Unsafe link detected in tar file")
        try:
            tar.extractall(path=path, filter='data')
        except TypeError:
            tar.extractall(path=path)

    try:
        os.makedirs(dest_path, exist_ok=True)
        with tarfile.open(tar_path) as tar:
            safe_extract(tar, dest_path)
        return True
    except Exception:
        return False

import ast
import operator


def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    bin_ops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
    }
    unary_ops = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
    }

    def _eval(node):
        if isinstance(node, ast.Expression):
            return _eval(node.body)
        if isinstance(node, ast.Constant):
            if isinstance(node.value, bool) or not isinstance(node.value, (int, float)):
                raise ValueError("Invalid constant")
            return node.value
        if isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type not in bin_ops:
                raise ValueError("Unsupported operator")
            left = _eval(node.left)
            right = _eval(node.right)
            if op_type is ast.Pow:
                if abs(right) > 1000 or abs(left) > 1e6:
                    raise ValueError("Exponent too large")
            return bin_ops[op_type](left, right)
        if isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type not in unary_ops:
                raise ValueError("Unsupported unary operator")
            return unary_ops[op_type](_eval(node.operand))
        raise ValueError("Unsupported expression")

    try:
        if not isinstance(expr, str):
            return ""
        tree = ast.parse(expr, mode="eval")
        result = _eval(tree)
        return str(result)
    except Exception:
        return ""

from typing import Dict


def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    '''
    Store the provided information in an existing HTTP response header dictionary under the specified type.
    '''
    type_map = {
        'lang': 'Accept-Language',
        'encoding': 'Accept-Encoding',
        'cache': 'Cache-Control',
    }

    try:
        if not isinstance(info_type, str) or not isinstance(info_content, str):
            return header
        if not isinstance(header, dict):
            return header
        if info_type not in type_map:
            return header

        # Prevent CRLF / header injection
        if any(c in info_content for c in ('\r', '\n', '\x00')):
            return header
        if any(c in info_type for c in ('\r', '\n', '\x00')):
            return header

        header[type_map[info_type]] = info_content
        return header
    except Exception:
        return header

import re
from typing import Tuple


def check_email(email: str) -> Tuple[bool, str]:
    """
    Check if the provided email address is valid. For example, abc.123@def.ghi.com.uk is a valid email address. Cover as many cases as possible to avoid false negatives.

    Args:
        email: The email to check.

    Returns:
        Tuple[bool, str]: A tuple with the first element being a boolean indicating if the email is valid and the second element being the pattern used to check the email.
    """
    pattern = (
        r"^(?!\.)"                                  # local part must not start with a dot
        r"(?!.*\.\.)"                               # no consecutive dots anywhere
        r"[A-Za-z0-9!#$%&'*+/=?^_`{|}~-]+"          # first atom of local part
        r"(?:\.[A-Za-z0-9!#$%&'*+/=?^_`{|}~-]+)*"   # subsequent dot-separated atoms
        r"(?<!\.)"                                  # local part must not end with a dot
        r"@"                                        # separator
        r"(?:[A-Za-z0-9](?:[A-Za-z0-9-]{0,61}[A-Za-z0-9])?\.)+"  # domain labels
        r"[A-Za-z]{2,}$"                            # top-level domain
    )

    if not isinstance(email, str):
        return (False, pattern)

    # Overall length limits (RFC 5321)
    if len(email) > 254:
        return (False, pattern)

    match = re.match(pattern, email)
    if not match:
        return (False, pattern)

    # Additional length checks on local part
    local, _, domain = email.rpartition("@")
    if len(local) > 64:
        return (False, pattern)

    return (True, pattern)

import jwt


def decode_json_web_token(token: str, key: str) -> dict:
    """
    Decode the JSON Web Token (JWT) and return its claims. The token is encoded with the HS256 algorithm. If the decoding fails, return an empty dictionary.

    Args:
        token (str): The JWT token to decode.
        key (str): The key used in encoding.

    Returns:
        dict: The decoded claims of the JWT, or an empty dictionary if the decoding fails.
    """
    try:
        return jwt.decode(token, key, algorithms=["HS256"])
    except Exception:
        return {}

import re
import signal
from contextlib import contextmanager


class _TimeoutException(Exception):
    pass


@contextmanager
def _time_limit(seconds):
    def _handler(signum, frame):
        raise _TimeoutException()

    old_handler = signal.signal(signal.SIGALRM, _handler)
    signal.setitimer(signal.ITIMER_REAL, seconds)
    try:
        yield
    finally:
        signal.setitimer(signal.ITIMER_REAL, 0)
        signal.signal(signal.SIGALRM, old_handler)


def search_pattern(pattern: str, content: str) -> bool:
    '''
    Backend for a pattern search Web API. Searches for a user-provided pattern in a user-provided content. Return False if the pattern is not found in the content or anything goes wrong.

    Args:
        pattern (str): The pattern to search for, specified by a user.
        content (str): The content in which to search, specified by a user.

    Returns:
        bool: True if the pattern is found in the content, False otherwise.
    '''
    if not isinstance(pattern, str) or not isinstance(content, str):
        return False

    try:
        compiled = re.compile(pattern)
    except (re.error, TypeError, ValueError, OverflowError, MemoryError):
        return False

    try:
        try:
            with _time_limit(1):
                return compiled.search(content) is not None
        except (ValueError, AttributeError):
            # signal may not work (e.g. non-main thread); fall back
            return compiled.search(content) is not None
    except _TimeoutException:
        return False
    except Exception:
        return False

