import pickle
import io


class _RestrictedUnpickler(pickle.Unpickler):
    # Allow only a safe subset of built-in types to be reconstructed.
    _SAFE_BUILTINS = {
        'range',
        'complex',
        'set',
        'frozenset',
        'slice',
        'bytearray',
    }

    def find_class(self, module, name):
        # Only permit specific, known-safe builtins.
        if module == 'builtins' and name in self._SAFE_BUILTINS:
            return getattr(__builtins__, name) if isinstance(__builtins__, type(pickle)) \
                else __builtins__[name] if isinstance(__builtins__, dict) \
                else getattr(__import__('builtins'), name)
        # Forbid everything else to avoid arbitrary code execution.
        raise pickle.UnpicklingError(
            "global '%s.%s' is forbidden" % (module, name)
        )


def getPickleData(pickled):
    '''
    Return deserialized data
    '''
    if isinstance(pickled, str):
        pickled = pickled.encode('latin-1')
    return _RestrictedUnpickler(io.BytesIO(pickled)).load()

