import base64
import io


class _SafeUnpickler(cPickle.Unpickler):
    """
    A restricted unpickler that only allows a safe set of built-in types.
    This prevents arbitrary code execution (CWE-502: Deserialization of
    Untrusted Data) when loading pickled data coming from request headers.
    """

    _ALLOWED = {
        ('builtins', 'dict'),
        ('builtins', 'list'),
        ('builtins', 'tuple'),
        ('builtins', 'set'),
        ('builtins', 'frozenset'),
        ('builtins', 'str'),
        ('builtins', 'bytes'),
        ('builtins', 'int'),
        ('builtins', 'float'),
        ('builtins', 'bool'),
        ('builtins', 'complex'),
        ('builtins', 'NoneType'),
    }

    def find_class(self, module, name):
        if (module, name) in self._ALLOWED:
            return super().find_class(module, name)
        raise cPickle.UnpicklingError(
            "Forbidden pickle global: %s.%s" % (module, name)
        )


def _safe_loads(data):
    return _SafeUnpickler(io.BytesIO(data)).load()


def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with cPickle to token object
    check if the token is valid and return the data  in token object if it is valid.
    '''
    try:
        raw_token = headers.get('AuthToken')
    except AttributeError:
        return None

    if not raw_token:
        return None

    # base64 decode
    try:
        if isinstance(raw_token, str):
            raw_token = raw_token.encode('utf-8')
        decoded = base64.b64decode(raw_token, validate=True)
    except Exception:
        return None

    # safely deserialize the token
    try:
        token = _safe_loads(decoded)
    except Exception:
        return None

    # validate token structure
    if not isinstance(token, dict):
        return None

    if not token.get('valid'):
        return None

    return token.get('data')

import base64
import json


def _safe_loads(data):
    """
    Safely deserialize token data using JSON instead of pickle.
    JSON is a text-based format that cannot execute arbitrary code,
    avoiding CWE-502: Deserialization of Untrusted Data.
    """
    if isinstance(data, (bytes, bytearray)):
        data = data.decode('utf-8')
    return json.loads(data)


